import numpy as np

def ensemble_classification(predictions, accuracies):
    total_accuracy = sum(accuracies)
    weighted_predictions = []
    for i in range(len(predictions)):
        weighted_predictions.append({k: v * accuracies[i] / total_accuracy for k, v in predictions[i].items()})
    ensemble_prediction = {}
    for prediction in weighted_predictions:
        for k, v in prediction.items():
            if k in ensemble_prediction:
                ensemble_prediction[k] += v
            else:
                ensemble_prediction[k] = v
    max_prob = max(ensemble_prediction.values())
    most_probable_class = [k for k, v in ensemble_prediction.items() if v == max_prob]
    confidence_level = max_prob
    return most_probable_class, confidence_level

